SELECT m.*, c.company_name, c.biz_reg_no, c.ceo_name, c.company_tel_no, c.ceo_mobile_no, c.zip_code, c.addr1, c.addr2, cr.channel_cd, cr.role_cd as admin_role_cd, b.member_grade_cd, b.managing_channel_cd, s.seller_type_cd FROM tb_member_master m LEFT JOIN tb_company_master c ON m.company_id = c.company_id LEFT JOIN tb_member_channel_role cr ON m.member_id = cr.member_id AND cr.use_yn = 'Y' AND cr.del_yn = 'N' LEFT JOIN tb_buyer_profile b ON m.member_id = b.member_id LEFT JOIN tb_seller_profile s ON m.member_id = s.member_id WHERE m.del_yn = 'N'
AND m.member_type_cd = #{memberType}
AND m.join_status_cd = #{status}
AND b.member_grade_cd = #{memberGrade}
AND cr.channel_cd = #{channelCd}
AND c.company_name LIKE CONCAT('%', #{searchKeyword}, '%')
AND m.login_id LIKE CONCAT('%', #{searchKeyword}, '%')
AND (c.company_name LIKE CONCAT('%', #{searchKeyword}, '%') OR m.login_id LIKE CONCAT('%', #{searchKeyword}, '%'))
ORDER BY m.member_id DESC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

SELECT COUNT(*) 
