INSERT INTO tb_company_master (
    company_name, biz_reg_no, ceo_name, company_tel_no, ceo_mobile_no, email, zip_code, addr1, addr2, company_status_cd, use_yn, del_yn, reg_id, reg_dt, mod_id, mod_dt
) VALUES (
    #{companyName}, #{bizRegNo}, #{ceoName}, #{companyTelNo}, #{ceoMobileNo}, #{email}, #{zipCode}, #{addr1}, #{addr2}, 'COMPANY_ACTIVE', 'Y', 'N', #{regId}, NOW(), #{regId}, NOW()
)

INSERT INTO tb_member_master (
    company_id, member_type_cd, login_id, login_pwd, member_name, mobile_no, email, join_status_cd, created_by_member_id, use_yn, del_yn, reg_id, reg_dt, mod_id, mod_dt
) VALUES (
    #{companyId}, #{memberTypeCd}, #{loginId}, #{loginPwd}, #{memberName}, #{mobileNo}, #{email}, #{joinStatusCd}, #{createdByMemberId}, 'Y', 'N', #{regId}, NOW(), #{regId}, NOW()
)

INSERT INTO tb_member_channel_role (
    member_id, company_id, channel_cd, role_cd, scope_cd, use_yn, del_yn, reg_id, reg_dt, mod_id, mod_dt
) VALUES (
    #{memberId}, #{companyId}, #{channelCd}, #{adminRoleCd}, 'CHANNEL', 'Y', 'N', #{regId}, NOW(), #{regId}, NOW()
)

INSERT INTO tb_buyer_profile (
    member_id, company_id, managing_channel_cd, member_grade_cd, credit_balance_amt, meatmoney_balance_amt, total_available_amt,
    month_order_amt, year_order_amt, total_order_amt, created_by_member_id, use_yn, reg_dt, mod_dt
) VALUES (
    #{memberId}, #{companyId}, #{managingChannelCd}, #{memberGradeCd}, 0, 0, 0, 0, 0, 0, #{createdByMemberId}, 'Y', NOW(), NOW()
)

INSERT INTO tb_seller_profile (
    member_id, company_id, seller_type_cd, tax_type_cd, created_by_member_id, use_yn, reg_dt, mod_dt
) VALUES (
    #{memberId}, #{companyId}, #{sellerTypeCd}, #{taxTypeCd}, #{createdByMemberId}, 'Y', NOW(), NOW()
)

INSERT INTO tb_seller_settlement_account (
    company_id, seller_member_id, bank_cd, account_no, account_name, default_yn, use_yn, reg_dt, mod_dt
) VALUES (
    #{companyId}, #{memberId}, #{bankCd}, #{accountNo}, #{accountName}, 'Y', 'Y', NOW(), NOW()
)

INSERT INTO tb_admin_profile (
    member_id, admin_role_cd, use_yn, reg_dt, mod_dt
) VALUES (
    #{memberId}, #{adminRoleCd}, 'Y', NOW(), NOW()
)

INSERT INTO tb_member_contact (
    MEMBER_ID, NAME, MOBILE_NO, PHONE_NO, EMAIL, CONTACT_TYPE_CD, USE_YN, REG_DT, MOD_DT
) VALUES (
    #{memberId}, #{name}, #{mobileNo}, #{phoneNo}, #{email}, #{contactTypeCd}, 'Y', NOW(), NOW()
)
